const express = require('express');
const app = express();
const port = 3000;

// 1. Request logging middleware
function requestLogger(req, res, next) {
  const start = Date.now();
  const originalEnd = res.end;

  res.end = function(...args) {
    const duration = Date.now() - start;
    console.log(`${req.method} ${req.originalUrl} ${res.statusCode} ${duration}ms`);
    originalEnd.apply(res, args);
  };

  next();
}

// 2. Authentication middleware
function authenticate(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  const token = authHeader.split(' ')[1];
  // Simple token validation (in real app, use JWT)
  if (token === 'valid-token') {
    req.user = { id: 1, name: 'Alice', role: 'admin' };
    next();
  } else {
    res.status(401).json({ error: 'Invalid token' });
  }
}

// 3. Role-based authorization middleware
function authorize(...roles) {
  return (req, res, next) => {
    if (!req.user || !roles.includes(req.user.role)) {
      return res.status(403).json({ error: 'Insufficient permissions' });
    }
    next();
  };
}

// 4. Validation middleware
function validateUser(req, res, next) {
  const { name, email } = req.body;

  if (!name || name.length < 2) {
    return res.status(400).json({ error: 'Name must be at least 2 characters' });
  }

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!email || !emailRegex.test(email)) {
    return res.status(400).json({ error: 'Valid email is required' });
  }

  next();
}

// 5. Error handling middleware
function errorHandler(err, req, res, next) {
  console.error('Error:', err.message);

  const status = err.status || 500;
  const message = err.message || 'Internal Server Error';

  res.status(status).json({
    error: {
      message,
      status,
      ...(process.env.NODE_ENV === 'development' && { stack: err.stack })
    }
  });
}

// Apply global middleware
app.use(express.json());
app.use(requestLogger);

// Public routes (no auth required)
app.get('/api/public', (req, res) => {
  res.json({ message: 'This is public data' });
});

// Protected routes (auth required)
app.get('/api/protected', authenticate, (req, res) => {
  res.json({ message: 'Protected data', user: req.user });
});

// Admin-only routes (auth + role required)
app.get('/api/admin', authenticate, authorize('admin'), (req, res) => {
  res.json({ message: 'Admin data', user: req.user });
});

// Routes with validation
app.post('/api/users', authenticate, validateUser, (req, res) => {
  res.status(201).json({ message: 'User created', user: req.body });
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Endpoint not found' });
});

// Error handler (must be last)
app.use(errorHandler);

app.listen(port, () => {
  console.log(`Server running on port ${port}`);
});
```

